function toMillis(v) {
  if (!v) return null;
  const d = new Date(v);
  const t = d.getTime();
  return Number.isNaN(t) ? null : t;
}

function isNetherlands(location) {
  const text = String(location || '').toLowerCase();
  const keys = ['netherlands', 'nederland', 'nl', 'amsterdam', 'rotterdam', 'utrecht', 'den haag', 'the hague', 'eindhoven'];
  return keys.some(k => text.includes(k));
}

const CV_KEYWORDS = ['sql','python','power bi','tableau','excel','etl','analytics','dashboard','stakeholder','experimentation'];

const now = Date.now();
const sevenDaysAgo = now - (7 * 24 * 60 * 60 * 1000);
const sd = this.getWorkflowStaticData('global');
if (!sd.seen) sd.seen = {};

const out = [];
for (const item of items) {
  const src = item.json || {};
  const rawTitle = src.title || '';
  const applyUrl = src.link || '';
  const dateRaw = src.isoDate || src.pubDate || null;
  const dateMs = toMillis(dateRaw);

  const parts = String(rawTitle).split(' - ').map(p => p.trim()).filter(Boolean);
  let title = rawTitle;
  let company = '';
  let location = '';
  if (parts.length >= 3) {
    title = parts[0];
    company = parts[1];
    location = parts.slice(2).join(' - ');
  } else if (parts.length === 2) {
    title = parts[0];
    company = parts[1];
  }

  const description = src.contentSnippet || src.content || src.summary || '';

  if (!applyUrl || !dateMs) continue;
  if (dateMs < sevenDaysAgo || dateMs > now + 24 * 60 * 60 * 1000) continue;
  if (!isNetherlands(location)) continue;

  const dedupeId = `indeed_nl_rss|${applyUrl}`;
  if (sd.seen[dedupeId]) continue;

  const text = `${title} ${description}`.toLowerCase();
  let score = 20;
  let hits = 0;
  for (const kw of CV_KEYWORDS) {
    if (text.includes(kw)) hits++;
  }
  score += Math.min(70, hits * 8);
  if (text.includes('data analyst')) score += 10;
  score = Math.max(0, Math.min(100, Math.round(score)));
  const matchLabel = score >= 75 ? 'High' : (score >= 50 ? 'Medium' : 'Low');

  sd.seen[dedupeId] = now;

  out.push({
    json: {
      datePosted: new Date(dateMs).toISOString(),
      title,
      company,
      location,
      matchScore: score,
      matchLabel,
      applyUrl,
      source: 'indeed_nl_rss'
    }
  });
}

return out;
